#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define INF 1e18

// Define the structure for a tree node
typedef struct Node {
    int H, C;
    struct Node** children;
    int numChildren;
} Node;

// Function to create a new node
Node* newNode(int H, int C) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->H = H;
    node->C = C;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}

// Function to add a child to a node
void addChild(Node* parent, Node* child) {
    parent->numChildren++;
    parent->children = (Node**)realloc(parent->children, parent->numChildren * sizeof(Node*));
    parent->children[parent->numChildren - 1] = child;
}

// Function to compute the minimum cost for a subtree rooted at a given node
long long computeCost(Node* node, int depth, int h, long long** memo) {
    if (memo[node->H][depth] != -1) return memo[node->H][depth];
    long long minCost = INF;
    // Consider each child as a potential starting point for a good path
    for (int i = 0; i < node->numChildren; i++) {
        Node* child = node->children[i];
        long long childCost = computeCost(child, depth + 1, h, memo);
        long long cost = childCost + node->C * (h - depth) + node->C * node->C - node->H;
        minCost = (minCost < cost) ? minCost : cost;
    }
    memo[node->H][depth] = minCost;
    return minCost;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node** nodes = (Node**)malloc(N * sizeof(Node*));
        for (int i = 0; i < N; i++) {
            int H, C;
            scanf("%d %d", &H, &C);
            nodes[i] = newNode(H, C);
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--; v--;
            addChild(nodes[u], nodes[v]);
        }
        int h = 0;
        for (int i = 0; i < N; i++) {
            if (nodes[i]->numChildren > 0) h++;
        }
        long long** memo = (long long**)malloc(N * sizeof(long long*));
        for (int i = 0; i < N; i++) {
            memo[i] = (long long*)malloc(h * sizeof(long long));
            for (int j = 0; j < h; j++) memo[i][j] = -1;
        }
        long long minCost = computeCost(nodes[0], 0, h, memo);
        printf("%lld\n", minCost);
        free(memo);
        free(nodes);
    }
    return 0;
}

