import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

// Define the structure for a tree node
class Node {
    int H, C;
    List<Node> children = new ArrayList<>();
    Node(int H, int C) {
        this.H = H;
        this.C = C;
    }
}

// Function to add a child to a node
void addChild(Node parent, Node child) {
    parent.children.add(child);
}

// Function to compute the minimum cost for a subtree rooted at a given node
long computeCost(Node node, int depth, int h, long[][] memo) {
    if (memo[node.H][depth] != -1) return memo[node.H][depth];
    long minCost = Long.MAX_VALUE;
    // Consider each child as a potential starting point for a good path
    for (Node child : node.children) {
        long childCost = computeCost(child, depth + 1, h, memo);
        long cost = childCost + node.C * (h - depth) + node.C * node.C - node.H;
        minCost = Math.min(minCost, cost);
    }
    memo[node.H][depth] = minCost;
    return minCost;
}

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            Node[] nodes = new Node[N];
            for (int i = 0; i < N; i++) {
                int H = scanner.nextInt();
                int C = scanner.nextInt();
                nodes[i] = new Node(H, C);
            }
            for (int i = 0; i < N - 1; i++) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                addChild(nodes[u], nodes[v]);
            }
            int h = 0;
            for (int i = 0; i < N; i++) {
                if (nodes[i].children.size() > 0) h++;
            }
            long[][] memo = new long[N][h];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < h; j++) memo[i][j] = -1;
            }
            long minCost = computeCost(nodes[0], 0, h, memo);
            System.out.println(minCost);
        }
    }
}

