class Node {
    constructor(H, C) {
        this.H = H;
        this.C = C;
        this.children = [];
    }
}

// Function to add a child to a node
function add_child(parent, child) {
    parent.children.push(child);
}

// Function to compute the minimum cost for a subtree rooted at a given node
function compute_cost(node, depth, h, memo) {
    if (memo[node.H][depth] !== -1) return memo[node.H][depth];
    let min_cost = Infinity;
    // Consider each child as a potential starting point for a good path
    for (let child of node.children) {
        let child_cost = compute_cost(child, depth + 1, h, memo);
        let cost = child_cost + node.C * (h - depth) + node.C * node.C - node.H;
        min_cost = Math.min(min_cost, cost);
    }
    memo[node.H][depth] = min_cost;
    return min_cost;
}

// Read input
let t = parseInt(input[idx++]);
for (let i = 0; i < t; i++) {
    let n = parseInt(input[idx++]);
    let nodes = [];
    for (let j = 0; j < n; j++) {
        let [H, C] = input[idx++].split(' ').map(Number);
